mapper.select:
select count(1)
from finance_currency_rate_history
where currency_code = #{currencyCode}

mapper.insert:
insert into finance_currency_sync_log(
    trace_id, sync_config_id, provider_code, request_url, request_time,
    response_time, cost_ms, status, error_code, error_message,
    currency_count, updated_count, response_summary, create_time
) values (
    #{traceId}, #{syncConfigId}, #{providerCode}, #{requestUrl}, #{requestTime},
    #{responseTime}, #{costMs}, #{status}, #{errorCode}, #{errorMessage},
    #{currencyCount}, #{updatedCount}, #{responseSummary}, #{createTime}
)

mapper.select:
select * from finance_currency_sync_log where 1 = 1
and trace_id like concat('%', #{traceId}, '%')
and provider_code = #{providerCode}
and status = #{status}
order by request_time desc, sync_log_id desc
